import os
import redis
import functools
import hashlib
import json
from flask import Flask, session, request, jsonify
from datetime import timedelta

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', 'your-secret-key-change-in-production')
app.config['SESSION_TYPE'] = 'redis'
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(hours=24)

REDIS_PASSWORD = os.environ.get('REDIS_PASSWORD')
if not REDIS_PASSWORD:
    raise ValueError("REDIS_PASSWORD environment variable must be set")

redis_client = redis.Redis(
    host=os.environ.get('REDIS_HOST', 'localhost'),
    port=int(os.environ.get('REDIS_PORT', 6379)),
    password=REDIS_PASSWORD,
    db=0,
    decode_responses=True,
    socket_connect_timeout=5,
    socket_timeout=5
)

try:
    redis_client.ping()
    print("Successfully connected to Redis")
except redis.ConnectionError as e:
    print(f"Failed to connect to Redis: {e}")
    raise


def cache_query(expiration=300):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key_data = {
                'func': func.__name__,
                'args': args,
                'kwargs': kwargs
            }
            cache_key = f"cache:{hashlib.md5(json.dumps(cache_key_data, sort_keys=True).encode()).hexdigest()}"
            
            try:
                cached_result = redis_client.get(cache_key)
                if cached_result:
                    return json.loads(cached_result)
            except redis.RedisError as e:
                print(f"Redis cache read error: {e}")
            
            result = func(*args, **kwargs)
            
            try:
                redis_client.setex(
                    cache_key,
                    expiration,
                    json.dumps(result)
                )
            except redis.RedisError as e:
                print(f"Redis cache write error: {e}")
            
            return result
        return wrapper
    return decorator


def set_user_session(user_id, user_data):
    session_key = f"session:{user_id}"
    try:
        redis_client.setex(
            session_key,
            int(app.config['PERMANENT_SESSION_LIFETIME'].total_seconds()),
            json.dumps(user_data)
        )
        session['user_id'] = user_id
        return True
    except redis.RedisError as e:
        print(f"Error setting user session: {e}")
        return False


def get_user_session(user_id):
    session_key = f"session:{user_id}"
    try:
        session_data = redis_client.get(session_key)
        if session_data:
            return json.loads(session_data)
        return None
    except redis.RedisError as e:
        print(f"Error getting user session: {e}")
        return None


def delete_user_session(user_id):
    session_key = f"session:{user_id}"
    try:
        redis_client.delete(session_key)
        session.pop('user_id', None)
        return True
    except redis.RedisError as e:
        print(f"Error deleting user session: {e}")
        return False


@cache_query(expiration=600)
def expensive_database_query(query_id):
    import time
    time.sleep(2)
    return {
        'query_id': query_id,
        'data': f'Result for query {query_id}',
        'records': [
            {'id': 1, 'name': 'Record 1'},
            {'id': 2, 'name': 'Record 2'},
            {'id': 3, 'name': 'Record 3'}
        ]
    }


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    user_id = data.get('user_id')
    username = data.get('username')
    
    if not user_id or not username:
        return jsonify({'error': 'user_id and username required'}), 400
    
    user_data = {
        'user_id': user_id,
        'username': username,
        'email': data.get('email', '')
    }
    
    if set_user_session(user_id, user_data):
        return jsonify({'message': 'Login successful', 'user': user_data}), 200
    else:
        return jsonify({'error': 'Failed to create session'}), 500


@app.route('/session', methods=['GET'])
def get_session():
    user_id = session.get('user_id')
    if not user_id:
        return jsonify({'error': 'No active session'}), 401
    
    user_data = get_user_session(user_id)
    if user_data:
        return jsonify({'user': user_data}), 200
    else:
        return jsonify({'error': 'Session not found'}), 404


@app.route('/logout', methods=['POST'])
def logout():
    user_id = session.get('user_id')
    if not user_id:
        return jsonify({'error': 'No active session'}), 401
    
    if delete_user_session(user_id):
        return jsonify({'message': 'Logout successful'}), 200
    else:
        return jsonify({'error': 'Failed to delete session'}), 500


@app.route('/query/<int:query_id>', methods=['GET'])
def query_data(query_id):
    user_id = session.get('user_id')
    if not user_id:
        return jsonify({'error': 'Authentication required'}), 401
    
    result = expensive_database_query(query_id)
    return jsonify(result), 200


@app.route('/cache/clear/<int:query_id>', methods=['DELETE'])
def clear_cache(query_id):
    user_id = session.get('user_id')
    if not user_id:
        return jsonify({'error': 'Authentication required'}), 401
    
    cache_key_data = {
        'func': 'expensive_database_query',
        'args': (query_id,),
        'kwargs': {}
    }
    cache_key = f"cache:{hashlib.md5(json.dumps(cache_key_data, sort_keys=True).encode()).hexdigest()}"
    
    try:
        redis_client.delete(cache_key)
        return jsonify({'message': f'Cache cleared for query {query_id}'}), 200
    except redis.RedisError as e:
        return jsonify({'error': f'Failed to clear cache: {str(e)}'}), 500


@app.route('/health', methods=['GET'])
def health():
    try:
        redis_client.ping()
        return jsonify({'status': 'healthy', 'redis': 'connected'}), 200
    except redis.RedisError as e:
        return jsonify({'status': 'unhealthy', 'redis': 'disconnected', 'error': str(e)}), 500


if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)